SELECT count(*) FROM movie_keyword, keyword, title, movie_companies, cast_info, role_type, movie_info WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_info.movie_id = title.id;